A multi-criteria scoring insertion with weighted regret look-ahead, penalized feasibility relaxation, incremental route repair swaps, and a forced-new-route fallback if all existing routes fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const REGRET_K = 2
	const SLACK_WEIGHT = 0.3
	const COMPACT_BONUS_FACTOR = 0.07
	const PENALTY_INFEASIBLE = 1e12
	const RELAXATION_ALPHA = 0.15
	for offset, ori := range oris {
		des := dess[offset]
		shipID := total_ship + offset
		type candInfo struct {
			idx       int
			rawDelta  float64
			score     float64
			afterCost float64
			validFeas bool
		}
		candidates := make([]candInfo, 0, dispatch.AssignsLen+1)
		bestFallbackIdx := -1
		bestFallbackIncrease := 1e18
		for i := 0; i < dispatch.AssignsLen; i++ {
			prevCost := dispatch.Assigns[i].Cost
			if prevCost < 0 {
				prevCost = dispatch.Assigns[i].AccumulatedCost
			}
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			var incr float64
			var feasible bool
			if newCost >= 0 && prevCost >= 0 {
				incr = newCost - prevCost
				feasible = true
			} else if newCost >= 0 {
				incr = newCost
				feasible = true
			} else {
				incr = PENALTY_INFEASIBLE
				feasible = false
			}
			if feasible && incr < bestFallbackIncrease {
				bestFallbackIncrease = incr
				bestFallbackIdx = i
			}
			slack := float64(dispatch.Assigns[i].StationCurrent.TimeEnd -
				dispatch.Assigns[i].StationCurrent.TimeStart + 1)
			if slack < 0 {
				slack = 0
			}
			normSlack := slack / 1440.0
			routeLen := float64(len(dispatch.Assigns[i].Stations))
			compactBonus := COMPACT_BONUS_FACTOR / (routeLen + 1.0)
			normalizer := prevCost + 1e-8
			if normalizer <= 0 {
				normalizer = 1e-3
			}
			weightedInc := incr / normalizer
			score := weightedInc - SLACK_WEIGHT*normSlack + compactBonus
			if !feasible {
				score += RELAXATION_ALPHA * routeLen
			}
			candidates = append(candidates, candInfo{
				idx:       i,
				rawDelta:  incr,
				score:     score,
				afterCost: newCost,
				validFeas: feasible,
			})
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}
		inserted := false
		if len(candidates) > 0 {
			for pass := 0; pass < len(candidates)-1; pass++ {
				for j := 0; j < len(candidates)-pass-1; j++ {
					if candidates[j].score > candidates[j+1].score {
						candidates[j], candidates[j+1] = candidates[j+1], candidates[j]
					}
				}
			}
			kLook := REGRET_K
			if kLook > len(candidates) {
				kLook = len(candidates)
			}
			regret := 0.0
			if kLook > 1 {
				regret = candidates[kLook-1].score - candidates[0].score
			}
			chosenIdx := candidates[0].idx
			regretThreshold := 0.0015
			if regret > regretThreshold {
				bestWeighted := candidates[0].score
				for cIdx := 0; cIdx < kLook; cIdx++ {
					routeLen := float64(len(dispatch.Assigns[candidates[cIdx].idx].Stations))
					penalty := 0.55 * (routeLen / 120.0)
					adjusted := candidates[cIdx].score - penalty
					if adjusted < bestWeighted {
						bestWeighted = adjusted
						chosenIdx = candidates[cIdx].idx
					}
				}
			} else {
				chosenIdx = candidates[0].idx
			}
			okTrial := dispatch.Assigns[chosenIdx].AddShip(shipID, ori, des)
			if okTrial {
				dispatch.Assigns[chosenIdx].GenRoute()
				if dispatch.Assigns[chosenIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[chosenIdx].RemoveShip(shipID)
					dispatch.Assigns[chosenIdx].GenRoute()
				}
			}
		}
		if !inserted && bestFallbackIdx >= 0 {
			okF := dispatch.Assigns[bestFallbackIdx].AddShip(shipID, ori, des)
			if okF {
				dispatch.Assigns[bestFallbackIdx].GenRoute()
				if dispatch.Assigns[bestFallbackIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestFallbackIdx].RemoveShip(shipID)
					dispatch.Assigns[bestFallbackIdx].GenRoute()
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ptr := &dispatch.Assigns[dispatch.AssignsLen]
			okSeed := ptr.AddShip(shipID, ori, des)
			if okSeed {
				ptr.GenRoute()
				if ptr.Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					ptr.RemoveShip(shipID)
					ptr.GenRoute()
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ptr := &dispatch.Assigns[dispatch.AssignsLen]
			okForce := ptr.AddShip(shipID, ori, des)
			if okForce {
				ptr.GenRoute()
				dispatch.AssignsLen++
				inserted = true
			}
		}
		for rIdx := 0; rIdx < dispatch.AssignsLen; rIdx++ {
			if len(dispatch.Assigns[rIdx].Stations) < 4 {
				continue
			}
			oldCost := dispatch.Assigns[rIdx].Cost
			improved := false
			for p := 1; p < len(dispatch.Assigns[rIdx].Stations)-2 && !improved; p++ {
				for q := p + 1; q < len(dispatch.Assigns[rIdx].Stations)-1 && !improved; q++ {
					stP := dispatch.Assigns[rIdx].Stations[p]
					stQ := dispatch.Assigns[rIdx].Stations[q]
					if stP.ReqCode == stQ.ReqCode || stP.Load != stQ.Load {
						continue
					}
					idP := p
					idQ := q
					if idP == idQ {
						continue
					}
					tmpOriP, tmpDesP := ori, des
					tmpOriQ, tmpDesQ := ori, des
					dispatch.Assigns[rIdx].RemoveShip(idP)
					dispatch.Assigns[rIdx].RemoveShip(idQ)
					addP := dispatch.Assigns[rIdx].AddShip(idP, tmpOriP, tmpDesP)
					addQ := dispatch.Assigns[rIdx].AddShip(idQ, tmpOriQ, tmpDesQ)
					if !(addP && addQ) {
						dispatch.Assigns[rIdx].GenRoute()
						dispatch.Assigns[rIdx].Cost = oldCost
						break
					}
					dispatch.Assigns[rIdx].GenRoute()
					if dispatch.Assigns[rIdx].Cost >= 0 && dispatch.Assigns[rIdx].Cost < oldCost {
						improved = true
					} else {
						dispatch.Assigns[rIdx].RemoveShip(idP)
						dispatch.Assigns[rIdx].RemoveShip(idQ)
						dispatch.Assigns[rIdx].AddShip(idP, tmpOriP, tmpDesP)
						dispatch.Assigns[rIdx].AddShip(idQ, tmpOriQ, tmpDesQ)
						dispatch.Assigns[rIdx].GenRoute()
						dispatch.Assigns[rIdx].Cost = oldCost
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

